+				value = objectData.data;
+			} else if (objectData.hasOwnProperty('value')) {
+				value = objectData.value;
+			}
+			map[objectData._key] = value;
+		});
+		return keys.map(key => (map.hasOwnProperty(key) ? map[key] : null));
+	};
+
 	module.set = async function (key, value) {
