--- a/src/database/postgres/main.js
+++ b/src/database/postgres/main.js
@@ -119,6 +119,28 @@ SELECT s."data" t
 		return res.rows.length ? res.rows[0].t : null;
 	};

+	module.mget = async function (keys) {
+		if (!Array.isArray(keys) || !keys.length) {
+			return [];
+		}
+
+		const res = await module.pool.query({
+			name: 'mget',
+			text: `
+SELECT s."data" t
+  FROM UNNEST($1::TEXT[]) WITH ORDINALITY k("_key", i)
+  LEFT OUTER JOIN "legacy_object_live" o
+               ON o."_key" = k."_key"
+  LEFT OUTER JOIN "legacy_string" s
+               ON o."_key" = s."_key"
+              AND o."type" = s."type"
+ ORDER BY k.i ASC`,
+			values: [keys],
+		});
+
+		return res.rows.map(row => (row.t === undefined ? null : row.t));
+	};
+
 	module.set = async function (key, value) {
 		if (!key) {
 			return;
